100→	qb := &queryBuilder{}
101→	qb.add("owner_id = $%d", ownerID)
102→	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
103→	applyFilter(qb, filter)
104→	whereClause := qb.where()
105→
106→	// Count total matches
107→	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
